SELECT ?player (COUNT(?match) AS ?derbyApps) WHERE {
  ?match wdt:P256 wd:Q9448 ; 
         wdt:P255 ?home_team ; 
         wdt:P1238 ?away_team ;
         wdt:P2216 ?player .
  ?home_team wdt:P159 ?home_city .
  ?away_team wdt:P159 ?away_city .
  FILTER (?home_city = ?away_city)
}
GROUP BY ?player
ORDER BY DESC(?derbyApps)
LIMIT 1

